const chefkoch = $('Fetch Chefkoch (Jina)').first();
const eatsmarter = $('Fetch EatSmarter (Jina)').first();
const lecker = $('Fetch Lecker (Jina)').first();

const extract = (node) => {
  try {
    const raw = node.json;
    return String(raw.data || raw.body || raw || '').substring(0, 6000);
  } catch(e) { return '[Nicht verfügbar]'; }
};

return [{ json: {
  chefkochText: extract(chefkoch),
  eatSmarterText: extract(eatsmarter),
  leckerText: extract(lecker)
} }];

const { chefkochText, eatSmarterText, leckerText } = $input.first().json;

const systemPrompt = `Du bist ein Ernährungsexperte. Du erhältst echten Inhalt von deutschen Rezept-Websites und extrahierst daraus strukturierte Rezeptdaten. Antworte ausschließlich mit validem JSON mit dem Key "recipes" als Array.`;

const userPrompt = `Hier ist echter Inhalt von drei deutschen Rezept-Websites. Extrahiere und strukturiere daraus GENAU 28 verschiedene Rezepte — 14 Mittagessen, 14 Abendessen. Jeder Rezeptname muss einzigartig sein.

=== CHEFKOCH.DE ===
${chefkochText}

=== EATSMARTER.DE ===
${eatSmarterText}

=== LECKER.DE ===
${leckerText}

Filter:
- Zubereitungszeit: unter 30 Minuten
- Vorwiegend vegetarisch ODER Geflügel ODER Fisch (kein Schalentier, kein roher Fisch)
- Hoher Proteingehalt
- Familienfreundlich
- Abwechselnde Küchenstile: Mediterran, Asiatisch, Deutsch, Orientalisch, Griechisch

Wenn die Websites zu wenig Rezepte liefern, ergänze passende Rezepte aus deinem Wissen.

Für jedes Rezept:
- name (string, einzigartig)
- source_url (string)
- cuisine (string)
- meal_type: "Mittagessen" oder "Abendessen"
- prep_time_minutes (Zahl)
- ingredients: Array von Strings mit metrischen Mengen, skaliert für 2.5 Portionen
- steps: Array von Strings
- calories_per_adult (Zahl)
- protein_per_adult_g (Zahl)
- child_adaptation (string oder null)
- expensive_ingredients: Array von {name, alternative} oder leer
- pregnancy_safe: true/false`;

const payload = {
  model: 'gpt-4o',
  response_format: { type: 'json_object' },
  messages: [
    { role: 'system', content: systemPrompt },
    { role: 'user', content: userPrompt }
  ]
};

return [{ json: { payload: JSON.stringify(payload) } }];

const response = $input.first().json;
let recipes = [];

try {
  const content = response.choices[0].message.content;
  const parsed = JSON.parse(content);
  recipes = parsed.recipes || Object.values(parsed)[0] || [];
} catch(e) {
  return [{ json: { error: 'Failed to parse recipes: ' + e.message, recipes: [] } }];
}

const FORBIDDEN = [
  'roher fisch','sushi','sashimi','ceviche','carpaccio','räucherlachs','roher lachs',
  'weichkäse','brie','camembert','roquefort','gorgonzola',
  'rohmilch','unpasteurisiert','leber'
];

const safeRecipes = recipes.filter(r => {
  if (r.pregnancy_safe === false) return false;
  const text = (r.ingredients || []).join(' ').toLowerCase() + ' ' + (r.name || '').toLowerCase();
  return !FORBIDDEN.some(f => text.includes(f));
});

console.log(`Rezepte gesamt: ${recipes.length}, schwangerschaftssicher: ${safeRecipes.length}`);
return [{ json: { recipes: safeRecipes } }];

// Assigns recipes to days deterministically — no GPT-4o, no duplicates possible.
const { recipes } = $input.first().json;

const DAYS = ['Montag','Dienstag','Mittwoch','Donnerstag','Freitag','Samstag','Sonntag'];

// Shuffle array (Fisher-Yates)
const shuffle = (arr) => {
  const a = [...arr];
  for (let i = a.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [a[i], a[j]] = [a[j], a[i]];
  }
  return a;
};

const lunches = shuffle(recipes.filter(r => r.meal_type === 'Mittagessen'));
const dinners = shuffle(recipes.filter(r => r.meal_type === 'Abendessen'));

// Pad with shuffled extras if fewer than 14 of either type
while (lunches.length < 14) lunches.push(...shuffle(recipes).slice(0, 14 - lunches.length));
while (dinners.length < 14) dinners.push(...shuffle(recipes).slice(0, 14 - dinners.length));

const meal_plan = DAYS.map((day, i) => ({
  day,
  lunch_option_1: lunches[i * 2].name,
  lunch_option_2: lunches[i * 2 + 1].name,
  dinner_option_1: dinners[i * 2].name,
  dinner_option_2: dinners[i * 2 + 1].name,
}));

// Build recipe lookup by name
const byName = {};
recipes.forEach(r => { byName[r.name] = r; });

// Build shopping lists in code — 100% accurate, no GPT guessing
const CATEGORIES = ['Gemüse & Obst','Proteine','Milch & Eier','Trockenwaren & Vorräte','Tiefkühl'];

const categorise = (ingredient) => {
  const s = ingredient.toLowerCase();
  if (/spinat|brokkoli|karott|paprika|zucchini|tomaten|zwiebel|knoblauch|avocado|aubergine|kohl|blumenkohl|salat|kräuter|basilikum|petersilie|mango|süßkartoffel|kartoffel|erbsen|bohnen|gurke|pilze|champignon|zitrone|limette/.test(s)) return 'Gemüse & Obst';
  if (/hähnchen|hühnchen|pute|tofu|tempeh|thunfisch|fisch|lachs|garnelen|kichererbsen|linsen|bohnen|feta|mozzarella|parmesan|käse|erdnuss/.test(s)) return 'Proteine';
  if (/ei|eier|joghurt|quark|sahne|milch|butter|ricotta|käse/.test(s)) return 'Milch & Eier';
  if (/tiefkühl|gefrier/.test(s)) return 'Tiefkühl';
  return 'Trockenwaren & Vorräte';
};

const buildList = (dayIndices) => {
  const consolidated = {};
  dayIndices.forEach(i => {
    const day = meal_plan[i];
    ['lunch_option_1','lunch_option_2','dinner_option_1','dinner_option_2'].forEach(slot => {
      const recipe = byName[day[slot]];
      if (!recipe) return;
      (recipe.ingredients || []).forEach(ing => {
        const key = ing.toLowerCase().replace(/[^a-zäöü]/g, '').substring(0, 15);
        if (!consolidated[key]) consolidated[key] = { name: ing, count: 1 };
        else consolidated[key].count += 1;
      });
    });
  });

  const list = {};
  CATEGORIES.forEach(c => list[c] = []);
  Object.values(consolidated).forEach(({ name, count }) => {
    const cat = categorise(name);
    const qty = count > 1 ? `×${count} (konsolidiert)` : '';
    list[cat].push({ name, quantity: qty });
  });
  return list;
};

const shopping_list_1 = buildList([0, 1, 2, 3]); // Mon–Thu
const shopping_list_2 = buildList([4, 5, 6]);    // Fri–Sun

return [{ json: { meal_plan, recipes, shopping_list_1, shopping_list_2 } }];

const { meal_plan, recipes, shopping_list_1, shopping_list_2 } = $input.first().json;

const mealPlanRows = meal_plan.map(day => `
  <tr>
    <td><strong>${day.day}</strong></td>
    <td>${day.lunch_option_1}<br><small style="color:#666">${day.lunch_option_2}</small></td>
    <td>${day.dinner_option_1}<br><small style="color:#666">${day.dinner_option_2}</small></td>
  </tr>`).join('');

const recipeCards = recipes.map(r => {
  const ingredients = (r.ingredients || []).map(i => `<li>${i}</li>`).join('');
  const steps = (r.steps || []).map(s => `<li>${s}</li>`).join('');
  const childNote = r.child_adaptation ? `<p><strong>👶 Für das Kind:</strong> ${r.child_adaptation}</p>` : '';
  const altNote = (r.expensive_ingredients || []).length > 0
    ? `<p><small>💡 Günstige Alternative: ${r.expensive_ingredients.map(e => `${e.name} → ${e.alternative}`).join(', ')}</small></p>`
    : '';
  return `
  <div style="border:1px solid #ddd;border-radius:8px;padding:16px;margin-bottom:16px;">
    <h3><a href="${r.source_url || '#'}" style="color:#40916c;">${r.name}</a></h3>
    <p>⏱ ${r.prep_time_minutes} Min &nbsp;|&nbsp; 🔥 ${r.calories_per_adult} kcal &nbsp;|&nbsp; 💪 ${r.protein_per_adult_g}g Protein &nbsp;|&nbsp; <span style="color:green">✅ Schwangerschaftssicher</span></p>
    <h4>Zutaten</h4><ul>${ingredients}</ul>
    <h4>Zubereitung</h4><ol>${steps}</ol>
    ${childNote}${altNote}
  </div>`;
}).join('');

const shoppingListHtml = (list, label) => {
  if (!list || typeof list !== 'object') return '';
  const categories = Object.entries(list).map(([cat, items]) => {
    if (!items.length) return '';
    const rows = items.map(item => `<li><strong>${item.name}</strong>${item.quantity ? ' — ' + item.quantity : ''}</li>`).join('');
    return `<h3>${cat}</h3><ul>${rows}</ul>`;
  }).join('');
  return `<h2>🛒 Einkaufsliste ${label}</h2>${categories}`;
};

const html = `<!DOCTYPE html>
<html lang="de">
<head>
  <meta charset="UTF-8">
  <style>
    body{font-family:Arial,sans-serif;max-width:800px;margin:auto;padding:20px;color:#333}
    h1{color:#2d6a4f} h2{color:#40916c;border-bottom:2px solid #40916c;padding-bottom:4px}
    h3{color:#52b788} table{width:100%;border-collapse:collapse}
    th,td{padding:8px;border:1px solid #ddd;vertical-align:top}
    th{background:#f5f5f5} a{color:#40916c}
    footer{text-align:center;color:#999;margin-top:40px;font-size:12px}
  </style>
</head>
<body>
  <h1>🥗 Dein Familien-Wochenplan</h1>
  <h2>📅 Wochenübersicht</h2>
  <table>
    <thead><tr><th>Tag</th><th>Mittagessen</th><th>Abendessen</th></tr></thead>
    <tbody>${mealPlanRows}</tbody>
  </table>
  <h2>📖 Rezeptkarten</h2>
  ${recipeCards}
  ${shoppingListHtml(shopping_list_1, 'Montag – Donnerstag')}
  ${shoppingListHtml(shopping_list_2, 'Freitag – Sonntag')}
  <footer>Erstellt von deinem Familien-Mahlzeitenplaner 🥦</footer>
</body>
</html>`;

return [{ json: { html, subject: 'Dein Wochenplan 🥗' } }];
